// HTML nümunəsi:
/*
<div id="noteElement">
  Salam, <strong>Dəftər!</strong>
  <span style="display: none;">Gizli qeyd</span>
</div>
<button class="update-btn">Məzmunu yenilə</button>
*/

// 1. innerHTML ilə işləmə
const noteElement = document.getElementById("noteElement");
console.log(noteElement.innerHTML);
// nəticə: "Salam, <strong>Dəftər!</strong>\n  <span style=\"display: none;\">Gizli qeyd</span>"

noteElement.innerHTML = "Yeni <em>qeyd</em>!";
// nəticə: <div id="noteElement">Yeni <em>qeyd</em>!</div>

// 2. innerText ilə işləmə
console.log(noteElement.innerText);
// nəticə: "Yeni qeyd!" (yalnız görünən mətn, HTML etiketləri yoxdur, gizli mətn nəzərə alınmır)

noteElement.innerText = "Sadə qeyd";
// nəticə: <div id="noteElement">Sadə qeyd</div> (HTML etiketləri silinir)

// 3. textContent ilə işləmə
console.log(noteElement.textContent);
// nəticə: "Sadə qeyd" (bütün mətn, HTML etiketləri və gizli mətn daxil olsa belə)

noteElement.textContent = "Xam mətn <strong>qeyd</strong>";
// nəticə: <div id="noteElement">Xam mətn &lt;strong&gt;qeyd&lt;/strong&gt;</div> (etiketlər mətn kimi görünür)

// 4. Hadisə ilə dinamik yeniləmə
const updateButton = document.querySelector(".update-btn");
updateButton.addEventListener("click", () => {
  noteElement.innerHTML = "<strong>Yenilənmiş</strong> qeyd!"; // HTML dəstəklənir
  // noteElement.innerText = "Yenilənmiş qeyd!"; // yalnız mətn
  // noteElement.textContent = "Yenilənmiş qeyd!"; // xam mətn
});
// nəticə: Düyməyə klikləyəndə məzmun yenilənir

// Təhlükə nümunəsi: innerHTML ilə XSS
const userInput = "<script>alert('Hücum!');</script>";
noteElement.innerHTML = userInput;
// Təhlükə: Zərərli skript işləyə bilər!

// Təhlükəsiz alternativ
noteElement.textContent = userInput;
// nəticə: <div id="noteElement">&lt;script&gt;alert('Hücum!');&lt;/script&gt;</div>

// innerText ilə görünən mətn
noteElement.innerHTML = "Görünən <span style=\"display: none;\">gizli</span> mətn";
console.log(noteElement.innerText); // "Görünən mətn"
console.log(noteElement.textContent); // "Görünən gizli mətn"

// Dinamik yeniləmə
const updateNote = () => {
  noteElement.textContent = "Təhlükəsiz yeniləmə";
  console.log("innerText: ", noteElement.innerText); // "Təhlükəsiz yeniləmə"
  console.log("textContent: ", noteElement.textContent); // "Təhlükəsiz yeniləmə"
};
updateButton.addEventListener("click", updateNote);
// nəticə: Düyməyə klikləyəndə məzmun təhlükəsiz yenilənir

