// HTML example:
/*
<div id="noteElement">
  Hello, <strong>Notepad!</strong>
  <span style="display: none;">Hidden note</span>
</div>
<button class="update-btn">Update Content</button>
*/

// 1. Working with innerHTML
const noteElement = document.getElementById("noteElement");
console.log(noteElement.innerHTML);
// Output: "Hello, <strong>Notepad!</strong>\n  <span style=\"display: none;\">Hidden note</span>"

noteElement.innerHTML = "New <em>note</em>!";
// Output: <div id="noteElement">New <em>note</em>!</div>

// 2. Working with innerText
console.log(noteElement.innerText);
// Output: "New note!" (only visible text, no HTML tags, hidden text ignored)

noteElement.innerText = "Simple note";
// Output: <div id="noteElement">Simple note</div> (HTML tags removed)

// 3. Working with textContent
console.log(noteElement.textContent);
// Output: "Simple note" (all text, even if HTML tags or hidden text were present)

noteElement.textContent = "Raw text <strong>note</strong>";
// Output: <div id="noteElement">Raw text &lt;strong&gt;note&lt;/strong&gt;</div> (tags rendered as text)

// 4. Dynamic update with event
const updateButton = document.querySelector(".update-btn");
updateButton.addEventListener("click", () => {
  noteElement.innerHTML = "<strong>Updated</strong> note!"; // Supports HTML
  // noteElement.innerText = "Updated note!"; // Only text
  // noteElement.textContent = "Updated note!"; // Raw text
});
// Output: Clicking the button updates the content

// Danger example: XSS with innerHTML
const userInput = "<script>alert('Attack!');</script>";
noteElement.innerHTML = userInput;
// Danger: Malicious script could run!

// Safe alternative
noteElement.textContent = userInput;
// Output: <div id="noteElement">&lt;script&gt;alert('Attack!');&lt;/script&gt;</div>

// innerText vs textContent
noteElement.innerHTML = "Visible <span style=\"display: none;\">hidden</span> text";
console.log(noteElement.innerText); // "Visible text"
console.log(noteElement.textContent); // "Visible hidden text"

// Dynamic update
const updateNote = () => {
  noteElement.textContent = "Safe update";
  console.log("innerText: ", noteElement.innerText); // "Safe update"
  console.log("textContent: ", noteElement.textContent); // "Safe update"
};
updateButton.addEventListener("click", updateNote);
// Output: Clicking the button safely updates the content

