// Пример HTML:
/*
<div id="noteElement">
  Привет, <strong>Блокнот!</strong>
  <span style="display: none;">Скрытая заметка</span>
</div>
<button class="update-btn">Обновить содержимое</button>
*/

// 1. Работа с innerHTML
const noteElement = document.getElementById("noteElement");
console.log(noteElement.innerHTML);
// Вывод: "Привет, <strong>Блокнот!</strong>\n  <span style=\"display: none;\">Скрытая заметка</span>"

noteElement.innerHTML = "Новая <em>заметка</em>!";
// Вывод: <div id="noteElement">Новая <em>заметка</em>!</div>

// 2. Работа с innerText
console.log(noteElement.innerText);
// Вывод: "Новая заметка!" (только видимый текст, без HTML-тегов, скрытый текст игнорируется)

noteElement.innerText = "Простая заметка";
// Вывод: <div id="noteElement">Простая заметка</div> (HTML-теги удаляются)

// 3. Работа с textContent
console.log(noteElement.textContent);
// Вывод: "Простая заметка" (весь текст, даже если были HTML-теги или скрытый текст)

noteElement.textContent = "Сырой текст <strong>заметка</strong>";
// Вывод: <div id="noteElement">Сырой текст &lt;strong&gt;заметка&lt;/strong&gt;</div> (теги отображаются как текст)

// 4. Динамическое обновление с событием
const updateButton = document.querySelector(".update-btn");
updateButton.addEventListener("click", () => {
  noteElement.innerHTML = "<strong>Обновлённая</strong> заметка!"; // Поддерживает HTML
  // noteElement.innerText = "Обновлённая заметка!"; // Только текст
  // noteElement.textContent = "Обновлённая заметка!"; // Сырой текст
});
// Вывод: При клике на кнопку содержимое обновляется

// Пример опасности: XSS с innerHTML
const userInput = "<script>alert('Атака!');</script>";
noteElement.innerHTML = userInput;
// Опасность: Вредоносный скрипт может выполниться!

// Безопасная альтернатива
noteElement.textContent = userInput;
// Вывод: <div id="noteElement">&lt;script&gt;alert('Атака!');&lt;/script&gt;</div>

// innerText против textContent
noteElement.innerHTML = "Видимый <span style=\"display: none;\">скрытый</span> текст";
console.log(noteElement.innerText); // "Видимый текст"
console.log(noteElement.textContent); // "Видимый скрытый текст"

// Динамическое обновление
const updateNote = () => {
  noteElement.textContent = "Безопасное обновление";
  console.log("innerText: ", noteElement.innerText); // "Безопасное обновление"
  console.log("textContent: ", noteElement.textContent); // "Безопасное обновление"
};
updateButton.addEventListener("click", updateNote);
// Вывод: При клике на кнопку содержимое безопасно обновляется

